onClick:
{{
  !emailloginCopy.text || !passwordloginCopy.text
    ? showAlert("Please enter email and password", "warning")
    : LoginUserProfile.run()
        .then((res) => {
         storeValue("profileId", res.id);
    storeValue("userEmail", res.email);
    storeValue("firstName", res.firstName);
    storeValue("lastName", res.lastName);

    showAlert("Login successful", "success");
    navigateTo("Homepage");
        })
        .catch((err) => {
          showAlert("Invalid email or password", "error");
          console.log(err);
        });
}}
